module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
); 
// TODO: Implement multi_16bit
// Note: You may use 'assign' for continuous assignment
//       Use 'always @(posedge clk)' for sequential assignment
//       Use 'always @(*)' for combinational assignment
reg [31:0] yout_r;
assign yout = yout_r;
reg [15:0] areg;
reg [15:0] breg;
reg [16:0] i;
reg done_r;
assign done = done_r;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
      i <= 16'd0;
    end else if(start) begin
      if(i < 16'd17) begin
        i <= i + 16'd1;
      end
    end else begin
      i <= 16'd0;
    end
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
      done_r <= 1'b0;
    end else if(i == 16'd16) begin
      done_r <= 1'b1;
    end else if(i == 16'd17) begin
      done_r <= 1'b0;
    end
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
      areg <= 16'd0;
      breg <= 16'd0;
      yout_r <= 32'd0;
    end else if(start) begin
      if(i == 16'd0) begin
        areg <= ain;
        breg <= bin;
      end
      if(i > 16'd0 && i < 16'd17) begin
        if(areg[i-1] == 1'b1) begin
          yout_r <= yout_r + (breg << (i-1));
        end
      end
    end
end
endmodule
